import Element from "@/types/elements/Element";
import MailOptions from "@/types/MailOptions";

export default class SaveFormat {
    date: Date;
    mailOptions: MailOptions;
    elementList: Element[];
    version: string;

    constructor(date: Date, mailOptions: MailOptions, elementList: Element[], version: string)  {
        this.date = date;
        this.mailOptions = mailOptions;
        this.elementList = elementList;
        this.version = version;
    }
}
