export default function generateLink(url: string, country: string, language: string, mcr: string, link_id: string, disclaimer = false) {
    if (isMailLink(url)) return url;
    if (isLinkWithoutHttpProtocol(url)) url = addHttps(url)
    if (isShortcutLink(url)) return url;
    if (isRedirectLink(url)) return redirectLink(country, mcr, language, disclaimer, link_id, url);

    const [cleanUrl, tag] = getTagFromLink(url);
    const finalUrl = addLanguage(cleanUrl, language);
    return iBankLink(finalUrl, mcr, language, disclaimer, link_id, tag);
}

export function generateWebVersionLink(url: string, language: string): string {
    if (isMailLink(url) || isRedirectLink(url)) return url;
    const [cleanUrl, tag] = getTagFromLink(url);
    return addLanguage(cleanUrl, language) + tag;
}

function redirectLink(country: string, mcr: string, language: string, disclaimer: boolean, link_id: string, url: string) {
    return `$feedbackHandlerUrl?mailId=$mailId&amp;url=https://www.swedbank.${country.toLowerCase()}/rdt?WT.seg_4=MCR_${mcr}_${language.toLowerCase()}&amp;SW.link=${disclaimer ? 'disc' : 'link'}_${link_id}&amp;WT.dcsvid=$mailId&amp;redirectlink=${url}`;
}

function iBankLink(url: string, mcr: string, language: string, disclaimer: boolean, link_id: string, tag: string) {
    return `$feedbackHandlerUrl?mailId=$mailId&amp;url=${url}${hasLanguage(url) ? '&amp;' : '?'}WT.seg_4=MCR_${mcr}_${language.toLowerCase()}&amp;SW.link=${disclaimer ? 'disc' : 'link'}_${link_id}&amp;WT.dcsvid=$mailId${tag}`;
}

export function addLanguage(url: string, language: string) {
    if (hasLanguage(url) || isMailServerLink(url)) return url;
    return url + "?language=" + language;
}

function addHttps(url: string):string {
    return `https://${url}`
}

export function getTagFromLink(url: string) {
    const splitUrl = url.split(/(?=#)/g, 2);
    const cleanUrl = splitUrl[0];
    const tag = splitUrl[1] ?? "";
    return [cleanUrl, tag];
}

export function isMailLink(url: string): boolean {
    return url.includes("mailto");
}

export function isMailServerLink(url: string): boolean {
    return url.includes("/kirjad/");
}

function isShortcutLink(url: string): boolean {
    return url.includes("swedbank.ee/fondid"); // add further examples
}

export function isLinkWithoutHttpProtocol(url: string): boolean {
    const pattern = /^(http:\/\/|https:\/\/)/;
    return !pattern.test(url);
}

export function isRedirectLink(url: string): boolean {
    return url.includes(".pdf") || !url.includes("swedbank") || (url.includes(".swedbank.") && !url.includes("www.swedbank"));
}

export function hasLanguage(url: string): boolean {
    return url.includes("?language=");
}
