<template>
  <v-theme-provider theme="light">
    <div class="editor-wrapper" style="border: black solid 2px; border-radius: 5px;" v-if="editor && editor.isEditable && isActive">
      <div class="d-flex justify-center flex-wrap pb-2 pt-1" id="buttons">
        <v-defaults-provider :defaults="defaults">
          <v-btn v-if="!limitedEditing" title="Bold" :color="editor.isActive('bold') ? 'black' : ''" @click="editor.chain().focus().toggleBold().run()">
            <v-icon>mdi-format-bold</v-icon>
          </v-btn>
          <v-btn title="Italic" :color="editor.isActive('italic') ? 'black' : ''" @click="editor.chain().focus().toggleItalic().run()">
            <v-icon>mdi-format-italic</v-icon>
          </v-btn>
          <v-btn v-if="!limitedEditing" title="Orange" :color="editor.isActive('textStyle', {color: '#fb4f00'}) ? 'black' : ''" @click="editor.chain().focus().toggleColor('#fb4f00').run()">
            <v-icon>mdi-format-color-fill</v-icon>
          </v-btn>
          <v-btn v-if="!limitedEditing" title="Disclaimer text" :color="editor.isActive('strike') ? 'black' : ''" @click="editor.chain().focus().toggleDisclaimer().toggleColor('#785F5F').run()">
            <v-icon>mdi-size-xs</v-icon>
          </v-btn>
          <LinkMenu :editor="editor" />
          <v-btn title="Subscript" :color="editor.isActive('subscript') ? 'black' : ''" @click="editor.chain().focus().toggleSubscript().run()">
            <v-icon>mdi-format-subscript</v-icon>
          </v-btn>
          <v-btn title="Superscript" :color="editor.isActive('superscript') ? 'black' : ''" @click="editor.chain().focus().toggleSuperscript().run()">
            <v-icon>mdi-format-superscript</v-icon>
          </v-btn>
          <div style="flex-basis: 100%; display: flex;justify-content: center">
            <v-btn v-if="!limitedEditing" title="Align Left" :color="editor.isActive({ textAlign: 'left' }) ? 'black' : ''" @click="editor.chain().focus().setTextAlign('left').run()">
              <v-icon>mdi-format-align-left</v-icon>
            </v-btn>
            <v-btn v-if="!limitedEditing" title="Align Center" :color="editor.isActive({ textAlign: 'center' }) ? 'black' : ''" @click="editor.chain().focus().setTextAlign('center').run()">
              <v-icon>mdi-format-align-center</v-icon>
            </v-btn>
            <v-btn v-if="!limitedEditing" title="Align Center" :color="editor.isActive({ textAlign: 'right' }) ? 'black' : ''" @click="editor.chain().focus().setTextAlign('right').run()">
              <v-icon>mdi-format-align-right</v-icon>
            </v-btn>
            <v-btn title="Undo" @click="editor.chain().focus().undo().run()">
              <v-icon>mdi-undo</v-icon>
            </v-btn>
            <v-btn title="Redo" @click="editor.chain().focus().redo().run()">
              <v-icon>mdi-redo</v-icon>
            </v-btn>
          </div>
        </v-defaults-provider>
      </div>
      <editor-content class="pb-2 px-2" :editor="editor"/>
    </div>
    <div v-else v-html="editor?.getHTML()"/>
  </v-theme-provider>
</template>

<script>
import {Editor, EditorContent, Extension} from '@tiptap/vue-3';
import Italic from '@tiptap/extension-italic';
import StarterKit from '@tiptap/starter-kit';
import Document from '@tiptap/extension-document';
import Text from '@tiptap/extension-text';
import Subscript from '@tiptap/extension-subscript';
import Superscript from '@tiptap/extension-superscript';
import Highlight from '@tiptap/extension-highlight';
import TextAlign from '@tiptap/extension-text-align';
import TextStyle from '@tiptap/extension-text-style';
import {HardBreak} from "@tiptap/extension-hard-break";
import Strike from "@tiptap/extension-strike";
import {defineComponent} from "vue";
import {Paragraph} from "@tiptap/extension-paragraph";
import {Typography} from "@tiptap/extension-typography";
import LinkMenu, { CustomLink, StyledLink } from '@/components/text/LinkMenu.vue';

export default defineComponent({
  components: {
    EditorContent,
    LinkMenu,
  },
  props: {
    modelValue: {
      type: String,
      default: '',
    },
    isActive: {
      type: Boolean,
      default: false,
    },
    backgroundColor: {
      type: String,
    },
    limitedEditing: {
      type: Boolean,
      default: false,
    },
    insideSmallElement: {
      type: Boolean,
      default: false,
    }
  },
  emits: ['update:modelValue'],
  data() {
    return {
      defaults: {
        VBtn: {
          variant: 'text',
          size: this.insideSmallElement ? 'small' : 'default',
        }
      },
      editor: null,
    }
  },

  watch: {
    modelValue(value) {
      // HTML
      const isSame = this.editor.getHTML() === value

      // JSON
      // const isSame = JSON.stringify(this.editor.getJSON()) === JSON.stringify(value)

      if (isSame) {
        return
      }

      this.editor.commands.setContent(value, false);
    },
  },
  mounted() {
    const CustomItalic = Italic.extend({
      renderHTML({HTMLAttributes}) {
        return ['i', HTMLAttributes, 0]
      }
    });
    // used purely as a Disclaimer slave
    const CustomStrike = Strike.extend({
      renderHTML({HTMLAttributes}) {
        return ['span', HTMLAttributes, 0]
      }
    });
    /*const CustomHighlight = Highlight.extend({
      renderHTML({HTMLAttributes}) {
        return ['em', HTMLAttributes, 0]
      }
    })*/
    this.editor = new Editor({
      extensions: [
        StarterKit,
        CustomItalic,
        Document,
        Paragraph,
        Text,
        Subscript,
        Superscript,
        Highlight,
        CustomLink,
        StyledLink,
        TextStyle,
        Disclaimer,
        Typography.configure({
          openDoubleQuote: "„",
          closeDoubleQuote: "“",
          openSingleQuote: "'",
          closeSingleQuote: "'",
        }),
        CustomStrike,
        HardBreak.extend({
          addKeyboardShortcuts() {
            return {
              Enter: () => this.editor.commands.setHardBreak()
            }
          }
        }),
        // color example: https://codesandbox.io/s/cz6ro?file=/src/App.vue
        Color,
        TextAlign.configure({
          types: ['heading', 'paragraph'],
        }),
      ],
      content: this.modelValue,
      editorProps: {
        // This section fixes 2 things about pasting text from MS Word. It does this by just removing textStyles entirely, things like bold, italic, sub/superscript etc. still work.
        // 1) removing empty spans from pasted content
        // 2) getting rid of <span style="color: [object Object]"> that would often happen, especially when the copied text was colored.
        transformPasted(text) {
          for (const item of text.content.content) {
            if (item.marks) item.marks = item.marks.filter(x => x.type.name !== "textStyle");
            for (const content of item.content.content) {
              if (content.marks) content.marks = content.marks.filter(x => x.type.name !== "textStyle");
            }
          }
          return text;
        },
      },
      onUpdate: () => {
        // HTML
        this.$emit('update:modelValue', this.editor.getHTML());
        
        // JSON
        // this.$emit('update:modelValue', this.editor.getJSON())
      },
    })
  },
  computed: {
  },

  beforeUnmount() {
    this.editor.destroy()
  },
})

export const Disclaimer = Extension.create({
  name: "disclaimer",

  addOptions: {
    types: ["strike"]
  },

  addGlobalAttributes() {
    return [
      {
        types: this.options.types,
        attributes: {
          style: {
            default: null,
            renderHTML: () => {
              return {
                style: `font-family:Roboto,sans-serif;font-size:14px;line-height:22px;color:#785f5f;padding:20px 0;`,
              };
            }
          }
        }
      }
    ];
  },

  addCommands() {
    return {
      toggleDisclaimer: () => ({commands}) => {
        return commands.toggleMark("strike", {style: 'height:102x;font-size:12px;line-height:12px;display:block;'});
      },
    };
  }
});

export const Color = Extension.create({
  name: "color",

  addOptions: {
    types: ["textStyle"]
  },

  addGlobalAttributes() {
    return [
      {
        types: this.options.types,
        attributes: {
          color: {
            default: null,
            renderHTML: (attributes) => {
              if (!attributes.color || attributes.color?.color === "") {
                return {};
              }
              return {
                style: `color: ${attributes.color}`
              };
            },
            parseHTML: (element) => {
              return {
                color: element.style.color.replace(/['"]+/g, "")
              };
            }
          }
        }
      }
    ];
  },

  addCommands() {
    return {
      toggleColor: (color) => ({commands}) => {
        return commands.toggleMark("textStyle", {color});
      },
    };
  }
});

</script>

<style lang="scss" scoped>
/* Basic editor styles */
.ProseMirror {
  > * + * {
    margin-top: 0.75em;
  }

  ul,
  ol {
    padding: 0 1rem;
  }

  h1,
  h2,
  h3,
  h4,
  h5,
  h6 {
    line-height: 1.1;
  }

  code {
    background-color: rgba(#616161, 0.1);
    color: #616161;
  }

  pre {
    background: #0D0D0D;
    color: #FFF;
    font-family: 'JetBrainsMono', monospace;
    padding: 0.75rem 1rem;
    border-radius: 0.5rem;

    code {
      color: inherit;
      padding: 0;
      background: none;
      font-size: 0.8rem;
    }
  }

  img {
    max-width: 100%;
    height: auto;
  }

  blockquote {
    padding-left: 1rem;
    border-left: 2px solid rgba(#0D0D0D, 0.1);
  }

  hr {
    border: none;
    border-top: 2px solid rgba(#0D0D0D, 0.1);
    margin: 2rem 0;
  }
}

#buttons {
  border-bottom: 2px solid black;
  margin: 5px 0 10px 0;
}

</style>
