import MailOptions from "@/types/MailOptions";
import {returnMCR} from "@/utils/generateHtml";
import {MessageCategory} from "@/types/MessageCategory";

const getAdobePixelTracking = (mailOptions: MailOptions) => `<img src="http://swedbankab.d3.sc.omtrdc.net/b/ss/swedbankabbballswedprod/1?c.&amp;email.&amp;country=${mailOptions.country.toLowerCase()}&amp;id=MCR_${returnMCR(mailOptions)}_${mailOptions.language.toLowerCase()}&amp;contact=$mailId&amp;event=open&amp;.email&amp;.c" width="1" height="1" alt="" style="display:none;">`
const gdwPixelTracking = '<img src="$feedbackHandlerUrl?img&amp;mailId=$mailId" width="1" height="1" alt="" style="display:none;">'
const isDirectMarketingEmail = (mailOptions: MailOptions) => mailOptions.messageCategory === MessageCategory.DirectMarketing;

export default function composeTrackingHtml (mailOptions: MailOptions) {
    const adobePixelTracking = getAdobePixelTracking(mailOptions);
    return isDirectMarketingEmail(mailOptions) ? `${adobePixelTracking}\n${gdwPixelTracking}` : adobePixelTracking;
}