import TipTap from "@/types/TipTap";

export default function getBulletPointsFromJson(json: TipTap) {
  const htmlList: string[] = [];
  if (!json.content || json.content.length === 0) return htmlList;
  json.content.forEach(bullets => {
    bullets.content?.forEach((listItem) => {
      if (!listItem.content) return;
      let htmlString = "";
      for (const item of listItem.content) {
        if (!item.marks) htmlString += item.text;
        else {
          let textStart = "";
          let textEnd = "";
          item.marks.forEach(mark => {
            const type = mark.type;
            switch (type) {
              case "italic":
                textStart += '<i>';
                textEnd += '</i>'
                break;
              case "bold":
                textStart += '<strong>';
                textEnd += '</strong>'
                break;
              case "link":
                textStart += `<a href="${mark.attrs?.href}" style="font-family:Roboto,sans-serif;font-size:16px;line-height:24px;color:#257886;text-decoration:underline;" target="_blank">`;
                textEnd += '</a>'
                break;
              case "subscript":
                textStart += '<sub>';
                textEnd += '</sub>'
                break;
              case "superscript":
                textStart += '<sup>';
                textEnd += '</sup>'
                break;
              case "textStyle":
                if (mark.attrs?.color === "rgb(237, 125, 49)" || mark.attrs?.color === "#FB4F00" ||
                    mark.attrs?.color.color === "rgb(237, 125, 49)" || mark.attrs?.color.color === "#FB4F00") {
                  textStart += '<span style="color: #FB4F00">';
                  textEnd += '</span>'
                }
                break;
            }
          });
          htmlString += textStart + item.text + textEnd;
        }
      }
      htmlList.push(htmlString);
    })
  })
  return htmlList;
}
