import IElement from "@/types/elements/IElement";
import {Element_Type} from "@/types/elements/ElementTypes";

export const DIV_BREAK_0 = '';
export const DIV_BREAK_12 = '<div style="height:12px;font-size:12px;line-height:12px;display:block;">&nbsp;</div>\n';
export const DIV_BREAK_20 = '<div style="height:20px;font-size:20px;line-height:20px;display:block;">&nbsp;</div>\n';

export default function getSpacing(elements: IElement[], elementIndex: number): string {
  if (!elements || elements.length == 0 || elementIndex > elements.length - 1) return DIV_BREAK_0;

  const element = elements[elementIndex];
  const nextValidElement = getNextValidElement(elements, elementIndex);
  if (!nextValidElement || [Element_Type.OFFER_HEADER, Element_Type.CONDITIONAL, Element_Type.CONDITIONAL, Element_Type.DISCLAIMER, Element_Type.LOGO].includes(nextValidElement.type)) return DIV_BREAK_0;

  if (element.type == Element_Type.CONDITIONAL) {
    const prevElement = getPreviousElement(elements, elementIndex);
    const nextElement = elementIndex + 1 < elements.length ? elements[elementIndex] : null;
    if (!prevElement || nextElement?.type === Element_Type.CONDITIONAL) return DIV_BREAK_0;
    else return getSpacing([prevElement, nextValidElement], 0);
  }

  if (
    (element.type == Element_Type.COLOR_BLOCK && nextValidElement.type == Element_Type.OFFER) ||
    (element.type == Element_Type.COLOR_BLOCK && nextValidElement.type == Element_Type.COLOR_BLOCK) ||
    (element.type == Element_Type.BULLET_POINTS && (nextValidElement.type == Element_Type.TEXT || nextValidElement.type == Element_Type.LINK)) ||
    (element.type == Element_Type.OFFER && nextValidElement.type == Element_Type.COLOR_BLOCK) ||
    (element.type == Element_Type.LINK && nextValidElement.type == Element_Type.TEXT) ||
    (element.type == Element_Type.TWO_COLUMNS && nextValidElement.type == Element_Type.TWO_COLUMNS) ||
    (element.type == Element_Type.HEADING && nextValidElement.type == Element_Type.BULLET_POINTS) ||
    (element.type == Element_Type.OFFER && nextValidElement.type == Element_Type.OFFER) ||
    (element.type == Element_Type.TEXT && (nextValidElement.type == Element_Type.BULLET_POINTS || nextValidElement.type == Element_Type.LINK))
    ) return DIV_BREAK_12;

  if (element.type == Element_Type.HEADING && nextValidElement.type == Element_Type.HEADING) return DIV_BREAK_0; // allows multiline headers
  if (element.type == Element_Type.LOGO && nextValidElement.type == Element_Type.HEADING) return DIV_BREAK_0;
  if (element.type == Element_Type.OFFER_HEADER && (nextValidElement.type == Element_Type.OFFER || nextValidElement.type == Element_Type.PARTNER_OFFER)) return DIV_BREAK_0; // allows multiline headers
  if (element.type == Element_Type.SIGNATURE && nextValidElement.type == Element_Type.OFFER) return DIV_BREAK_20;

  if (
    [
      Element_Type.BULLET_POINTS,
      Element_Type.BUTTON,
      Element_Type.COLOR_BLOCK,
      Element_Type.IMAGE,
      Element_Type.LINK,
      Element_Type.LINK_AND_BUTTON,
      Element_Type.TWO_COLUMNS,
    ].includes(element.type) ||
    [
      Element_Type.BULLET_POINTS,
      Element_Type.BUTTON,
      Element_Type.COLOR_BLOCK,
      Element_Type.OFFER,
      Element_Type.TWO_COLUMNS,
      Element_Type.LINK,
      Element_Type.SIGNATURE,
    ].includes(nextValidElement.type)
  ) {
    return DIV_BREAK_20;
  }

  return DIV_BREAK_12;
}

/**
 * Returns the next valid i.e. non-Conditional element in the element list.
 *
 * @param elements - element list
 * @param index - index of the current element from which searching begins
 * @returns The next non-Conditional element in the list after the current element, or null if there is none.
 */
export function getNextValidElement(elements: IElement[], index: number) {
  return elements.find((element, currentIndex) =>
    currentIndex > index && element.type !== Element_Type.CONDITIONAL
  ) || null;
}

export function getPreviousElement(elements: IElement[], index: number) {
  return elements.slice(0, index).reverse().find(element =>
    element.type !== Element_Type.CONDITIONAL
  ) || null;
}
