<template>
  <v-theme-provider theme="light">
    <div style="border: black solid 2px; border-radius: 5px">
      <div class="d-flex justify-center flex-wrap pb-2 pt-1" id="buttons" v-if="editor && editor.isEditable && isActive">
        <v-defaults-provider :defaults="defaults">
          <v-btn title="Bold" :color="editor.isActive('bold') ? 'black' : ''" variant="flat" @click="editor.chain().focus().toggleBold().run()">
            <v-icon>mdi-format-bold</v-icon>
          </v-btn>
          <v-btn title="Italic" :color="editor.isActive('italic') ? 'black' : ''" variant="flat" @click="editor.chain().focus().toggleItalic().run()">
            <v-icon>mdi-format-italic</v-icon>
          </v-btn>
          <v-btn title="Orange" :color="editor.isActive('textStyle', {color: '#fb4f00'}) ? 'black' : ''" variant="flat" @click="editor.chain().focus().toggleColor('#fb4f00').run()">
            <v-icon>mdi-format-color-fill</v-icon>
          </v-btn>
          <LinkMenu :editor="editor" />
          <v-btn title="Subscript" :color="editor.isActive('subscript') ? 'black' : ''" variant="flat" @click="editor.chain().focus().toggleSubscript().run()">
            <v-icon>mdi-format-subscript</v-icon>
          </v-btn>
          <v-btn title="Superscript" :color="editor.isActive('superscript') ? 'black' : ''" variant="flat" @click="editor.chain().focus().toggleSuperscript().run()">
            <v-icon>mdi-format-superscript</v-icon>
          </v-btn>
          <div style="flex-basis: 100%; display: flex;justify-content: center">
            <v-btn title="Undo" variant="flat" @click="editor.chain().focus().undo().run()">
              <v-icon>mdi-undo</v-icon>
            </v-btn>
            <v-btn title="Redo" variant="flat" @click="editor.chain().focus().redo().run()">
              <v-icon>mdi-redo</v-icon>
            </v-btn>
          </div>
        </v-defaults-provider>
      </div>
      <editor-content :editor="editor" :style="isActive ? 'margin:10px 24px' : ''" />
    </div>
  </v-theme-provider>
</template>

<script>
import {Editor, EditorContent, Extension} from '@tiptap/vue-3';
import Italic from '@tiptap/extension-italic';
import StarterKit from '@tiptap/starter-kit';
import Text from '@tiptap/extension-text';
import Subscript from '@tiptap/extension-subscript';
import Superscript from '@tiptap/extension-superscript';
import Highlight from '@tiptap/extension-highlight';
import Link from '@tiptap/extension-link';
import TextStyle from '@tiptap/extension-text-style';
import {ListItem} from "@tiptap/extension-list-item";
import LinkMenu from '@/components/text/LinkMenu.vue';

export default {
  components: {
    EditorContent,
    LinkMenu
  },
  props: {
    modelValue: {
      type: String,
      default: '',
    },
    isActive: {
      type: Boolean,
      default: false
    },
    backgroundColor: {
      type: String,
    }
  },
  emits: ['update:modelValue'],
  data() {
    return {
      defaults: {
        VBtn: {
          variant: 'text',
          size: this.insideSmallElement ? 'small' : 'default',
        }
      },
      editor: null,
    }
  },

  watch: {
    modelValue(value) {
      // HTML
      // const isSame = this.editor.getHTML() === value

      // JSON
      const isSame = JSON.stringify(this.editor.getJSON()) === JSON.stringify(value)

      if (isSame) {
        return
      }

      this.editor.commands.setContent(value, false)
    },
  },
  mounted() {
    const CustomItalic = Italic.extend({
      renderHTML({HTMLAttributes}) {
        return ['i', HTMLAttributes, 0]
      }
    });
    this.editor = new Editor({
      extensions: [
        StarterKit,
        CustomItalic,
        // Paragraph,
        Text,
        Subscript,
        Superscript,
        Highlight,
        Link.configure({
          openOnClick: false,
        }),
        ListItem.extend({
          // keeps box as bulletList and also removes <p> tags https://github.com/ueberdosis/tiptap/issues/118#issuecomment-977114666
          // https://tiptap.dev/api/schema
          content: 'text*'
        }),
        TextStyle,
        // color example: https://codesandbox.io/s/cz6ro?file=/src/App.vue
        Color,
      ],
      content: this.modelValue,
      onUpdate: () => {
        // HTML
        // this.$emit('update:modelValue', this.editor.getHTML());

        // JSON
        this.$emit('update:modelValue', this.editor.getJSON())
      },
    })
  },

  beforeUnmount() {
    this.editor.destroy()
  },
}

const Color = Extension.create({
  name: "color",

  addOptions: {
    types: ["textStyle"]
  },

  addGlobalAttributes() {
    return [
      {
        types: this.options.types,
        attributes: {
          color: {
            default: null,
            renderHTML: (attributes) => {
              if (!attributes.color) {
                return {};
              }

              return {
                style: `color: ${attributes.color}`
              };
            },
            parseHTML: (element) => {
              return {
                color: element.style.color.replace(/['"]+/g, "")
              };
            }
          }
        }
      }
    ];
  },

  addCommands() {
    return {
      toggleColor: (color) => ({ commands }) => {
        return commands.toggleMark("textStyle", { color });
      },
    };
  }
});

</script>

<style scoped lang="scss">
/* Basic editor styles */
.ProseMirror {
  > * + * {
    margin-top: 0.75em;
  }

  ul, ol {
    padding: 0 1rem;
  }

  h1, h2, h3, h4, h5, h6 {
    line-height: 1.1;
  }

  code {
    background-color: rgba(#616161, 0.1);
    color: #616161;
  }

  pre {
    background: #0D0D0D;
    color: #FFF;
    font-family: 'JetBrainsMono', monospace;
    padding: 0.75rem 1rem;
    border-radius: 0.5rem;

    code {
      color: inherit;
      padding: 0;
      background: none;
      font-size: 0.8rem;
    }
  }

  img {
    max-width: 100%;
    height: auto;
  }

  blockquote {
    padding-left: 1rem;
    border-left: 2px solid rgba(#0D0D0D, 0.1);
  }

  hr {
    border: none;
    border-top: 2px solid rgba(#0D0D0D, 0.1);
    margin: 2rem 0;
  }
}

#buttons {
  border-bottom: 2px solid black;
  margin: 5px 0 10px 0;
}
</style>
